module top_module(clk, rst, A, B);input clk, rst;
   input [3:0] A;
   output [3:0] B;

   reg [3:0] A_reg;

   wire inverted_A_reg = ~A_reg + 1;
   assign B = inverted_A_reg;

   always @(posedge clk)
      begin
         if (rst)
            A_reg <= 4'b0;
         else
            A_reg <= A;
      end

endmodule
